import json
lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))

# Check for any key containing "exception", "reason", "message" etc
def search_keys(obj, prefix=""):
    if isinstance(obj, dict):
        for k, v in obj.items():
            path = f"{prefix}.{k}" if prefix else k
            if any(term in k.lower() for term in ['exception','reason','message','error','info','note','nsexception']):
                print(f"  {path}: {repr(v)[:200]}")
            if isinstance(v, (dict, list)):
                search_keys(v, path)
    elif isinstance(obj, list):
        for i, item in enumerate(obj):
            if isinstance(item, (dict, list)):
                search_keys(item, f"{prefix}[{i}]")

print("=== Keys containing exception/reason/message/error/info ===")
search_keys(crash)
